INSERT INTO scripture_verses (reference, version, text) VALUES
  ('Deut. 17:9', 'CEB', 'Ngadto kamo sa kaparian ug sa maghuhukom nga atua didto ug adto kamo magpakisayod kanila'),
  ('Neh. 8:8', 'CEB', 'Mihatag silag binaba nga hubad sa Balaod sa Dios, ug gipasabot kini aron ang mga tawo makasabot niini'),
  ('Mal. 2:7', 'CEB', 'Katungdanan sa mga pari ang pagtudlo sa matuod nga kaalam mahitungod sa Dios. Kinahanglan adto kanila ang akong katawhan magpakisayod bahin sa akong kabubut-on, kay sila mao man ang sinugo sa Ginoo nga Labing Gamhanan'),
  ('Mat. 16:18', 'CEB', 'Ikaw si Pedro ug sa ibabaw niining bato pagatukoron ko ang akong iglesya, ug bisan ang mga ganghaan sa hades dili makabuntog niini'),
  ('Luc. 6:13', 'CEB', 'Pagkaadlaw na, gitawag niya ang iyang mga tinun-an ug gipili niya ang 12 kanila nga ginganlan niyag apostoles'),
  ('Mat. 28:19-20', 'CEB', 'Gihatag kanako ang tanang gahom sa langit ug sa yuta. Busa panlakaw kamo ngadto sa tanang katawhan sa tibuok kalibotan ug himoa sila nga akong mga tinun-an, ug bunyagi sila sa ngalan sa Amahan, sa Anak, ug sa Espiritu Santo, ug tudloi sila sa pagtuman sa tanan nga akong gisugo kaninyo. Ug hinumdomi! Ako mag-uban kaninyo sa kanunay hangtod sa kataposan sa kalibotan'),
  ('Mat. 10:14-15', 'CEB', 'Ug kon anaay balay o lungsod nga dili modawat kaninyo o dili mamati kaninyo… sa Adlaw sa Paghukom mas maluoy pa ang Dios sa mga tawo sa Sodoma ug Gomora kay sa mga tawo nianang lungsora'),
  ('Gal. 1:8', 'CEB', 'Apan bisan kon kami, o usa ka anghel gikan sa langit, magwali kaninyo ug ebanghelyo nga lahi sa among giwali, ipatunglo siya'),
  ('1 Tes. 2:13', 'CEB', 'kay sa among pagwali kaninyo sa iyang mensahe namati kamo ug gidawat ninyo kini dili ingon nga iya sa tawo kondili iya gayod sa Dios'),
  ('Jn. 21:25', 'CEB', 'kon gisulat pa ang tanan… ang tibuok kalibotan dili paigo nga kasudlan sa mga sinulat'),
  ('2 Ped. 3:16', 'CEB', 'May mga butang nga lisod sabton sa iyang mga sulat, nga gituis sa mga walay alamag ug sa mga matuotuohon sama sa ilang gihimo sa ubang bahin sa Kasulatan, ug sa ingon nagtukmod sa ilang kaugalingon ngadto sa kalaglagan'),
  ('1 Cor. 4:6', 'CEB', 'ayaw kamo pagdawat og pagtulon-an nga kapin sa nasulat'),
  ('1 Cor. 14:37', 'CEB', 'kinahanglan ilhon niya nga ang gisulat ko kaninyo sugo sa Ginoo… apan kon dili siya magtagad nini, ayaw siyag tagda'),
  ('Mat. 15:6', 'CEB', 'tungod sa inyong mga tradisyon inyong gipakawalay pulos ang pulong sa Dios'),
  ('Isa. 59:21', 'CEB', 'ug ang akong mga pulong nga gipasulti ko kaninyo, dili gayod mawala diha sa inyong baba ni sa baba sa inyong mga anak ug mga apo sukad karon ug hangtod sa kahangtoran'),
  ('2 Tes. 2:15', 'CEB', 'mga igsoon hupti ninyo nga malig-on ang mga pagtulon-an nga among gitudlo kaninyo pinaagi sa among mga sulat o sa among tradisyon'),
  ('2 Tes. 3:6', 'CEB', 'likayi ninyo kadtong dili modawat sa atong tradisyon'),
  ('Jn. 5:39', 'CEB', 'susiha ninyo ang Kasulatan kay diha kanila makakaplag kamo sa kinabuhing dayon'),
  ('Jn. 20:31', 'CEB', 'apan kini gisulat aron kamo motuo nga si Jesus mao ang Mesiyas… ug pinaagi sa maong pagtuo makabaton kamo ug kinabuhi diha sa iyang ngalan'),
  ('2 Tim. 3:16-17', 'CEB', 'Ang tibuok Kasulatan gisulat uban sa lamdag sa Dios ug mapuslanon kini alang sa pagtudlo, sa pagsaway, ug sa pagtudlo unsaon sa pagkinabuhing matarong, aron ang nag-alagad sa Dios masangkap pag-ayo ug maandam sa tanang maayong buhat'),
  ('Mat. 24:4-5', 'CEB', 'Pagbantay kamo ug ayaw kamo palimbong ni bisan kinsa, kay sa akong ngalan daghang tawo ang moanhi nga mag-ingon, ‘Ako ang Mesiyas!’ ug daghan ang malimbongan'),
  ('Mat. 24:24', 'CEB', 'Kay manungha ang mga mini nga Mesiyas ug mga mini nga propeta; maghimo silag mga dagkong milagro ug mga katingalahan aron pagpasalaag sa mga pinili sa Dios, kon mahimo pa'),
  ('2 Cor. 11:13', 'CEB', 'Dili sila matuod nga mga apostoles kondili mga mini nga namakak mahitungod sa ilang buhat ug nag-usab sa ilang kaugalingon aron mahisama gayod sila sa matuod nga mga apostoles ni Cristo'),
  ('1 Jn. 2:19', 'CEB', 'Kining mga tawhana dili tinuod nga sakop sa atong pundok, busa namulag sila kanato. Kon tinuod pang ato silang mga kauban, magpabilin unta sila kanato. Apan namiya sila aron maila gayod nga sila dili kauban nato'),
  ('Jud. 1:18-19', 'CEB', 'Motungha ang mga tawo nga magbiaybiay kaninyo- mga tawo nga nagsunod sa ilang mga daotang tinguha. Sila maoy hinungdan sa pagkabahinbahin'),
  ('Dan. 2:44', 'CEB', 'Sa panahon niining mga haria ang Dios magtukod ug usa ka gingharian nga dili gayod malumpag'),
  ('Jn. 17:11', 'CEB', 'Balaang Amahan, bantayi sila diha sa gahom sa imong ngalan- ang ngalan nga imong gihatag kanako, aron sila mausa ingon nga ikaw ug ako usa lamang'),
  ('Efeso 4:4-5', 'CEB', 'May usa lamang ka lawas ug usa ka Espiritu, ingon nga may usa lamang ka paglaom… May usa lamang ka Ginoo, usa ka pagtuo'),
  ('Gal. 1:6-8', 'CEB', 'Ang tinuod, walay ‘laing ebanghelyo,’ apan gisulti ko kini kay may mga tawo man nga nagsamok kaninyo ug naninguha pagtuis sa ebanghelyo ni Cristo…kon may magwali kaninyo ug ebanghelyo nga lahi sa inyong nadawat, matinunglo siya'),
  ('Jn. 10:16', 'CEB', 'mahimo silang usa na lamang ka panon ubos sa usa ka magbalantay'),
  ('Jn. 21:15-17', 'CEB', 'Atimana ang akong mga nating karnero… Atimana ang akong mga karnero'),
  ('Buh. 2:42', 'CEB', 'Ug gigamit nila ang ilang panahon pagpamati sa mga gitudlo sa mga apostoles,… ug sa pagpikaspikas sa tinapay ug sa mga pag-ampo'),
  ('1 Cor. 10:17', 'CEB', 'Sanglit may usa lamang ka pan, kitang tanan bisan daghan, usa lamang ka lawas; kay nakig-ambit man kita sa usa lamang ka pan'),
  ('1 Ped. 2:9', 'CEB', 'Apan kamo mao ang piniling katawhan, ang mga harianong pari, ug ang balaang nasod'),
  ('Rom. 11:16', 'CEB', 'Kon balaan ang unang tipik sa pan nga gihalad ngadto sa Dios, balaan usab ang kinatibuk-an niini; ug kon balaan ang mga gamot sa kahoy, balaan usab ang mga sanga'),
  ('Mat. 28:20', 'CEB', 'tudloi sila sa pagtuman sa tanan nga akong gisugo kaninyo'),
  ('1 Cor. 4:1', 'CEB', 'Isipa kami nga mga sulugoon ni Cristo nga gitugyanan sa mga tinagong kamatuoran sa Dios'),
  ('Jn. 15:16', 'CEB', 'ug gipili ko kamo aron manlakaw ug mamungag daghan- mga bunga nga molungtad'),
  ('Mat. 13:47', 'CEB', 'Ang Gingharian sa langit sama usab sa usa ka baling nga gitaktak didto sa lanaw, nga nakakuha sa tanang matang sa isda'),
  ('Mat. 9:13', 'CEB', 'wala moanhi aron sa pagtawag sa mga matarong kondili sa mga makasasala aron sila maghinulsol'),
  ('2 Tes. 2:10', 'CEB', 'kay wala man nila dawata ug higugmaa ang kamatuoran nga makaluwas unta kanila'),
  ('Isa. 2:2', 'CEB', 'Sa umaabot nga mga adlaw ang bukid diin nahimutang ang Templo mahimong labing taas sa tanan… Daghang kanasoran mag-ambahan sa pag-adto didto'),
  ('Efeso 2:20', 'CEB', 'Gitukod kamo diha sa sukaranan nga mao ang mga apostoles'),
  ('Jn. 20:21', 'CEB', 'Ingon nga gipadala ako sa Amahan, ako usab nagpadala kaninyo'),
  ('Mat. 16:18-19', 'CEB', 'Ikaw si Pedro ug sa ibabaw niining maong bato tukoron ko ang akong Iglesya ug bisan gani ang mga ganghaan sa hades dili makabuntog niini. Ihatag ko kanimo (ngadto ni Pedro) ang mga yawi sa gingharian sa langit. Ang imong gapuson dinhi sa yuta gapuson usab didto sa langit ug ang imong hubaran sa yuta mahinubaran usab didto sa langit'),
  ('Buh. 14:23', 'CEB', 'Sa matag iglesia nagtudlo sila ug mga pangulo; ug uban sa mga pag-ampo ug pagpuasa ilang gitugyan sila ngadto sa Ginoo'),
  ('Gen. 1:26', 'CEB', 'buhaton nato ang tawo sama sa atong larawan ug panagway'),
  ('Gen. 11:7', 'CEB', 'manaog kita ug libogon ta ang ilang pinulongan'),
  ('Isa. 6:8', 'CEB', 'Kinsa man akong ipadala? Ug kinsa man ang moadto alang kanamo?'),
  ('Isa. 48:16', 'CEB', 'ang Dios ug ang iyang Espiritu maoy nagpadala kanako'),
  ('Luc. 1:35', 'CEB', 'mokunsad kanimo ang Espiritu Santo ug ang gahom sa Dios magpabilin diha kanimo. Tungod niini ang balaan nga bata pagatawgon nga Anak sa Dios'),
  ('Luc. 3:22', 'CEB', 'kini ang pinangga kong Anak nga gikahimut-an ko pag-ayo'),
  ('Juan 14:16', 'CEB', 'Mangayo ko sa Amahan ug iyang ipadala kaninyo ang laing Manlalaban, ang Espiritu sa kamatuoran'),
  ('Mat. 28:19', 'CEB', 'panlakaw kamo ngadto sa tibuok kalibotan ug himoa sila nga akong mga tinun-an, ug bunyagi sila sa ngalan sa Amahan, sa Anak ug sa Espiritu Santo'),
  ('Buh. 2:38', 'CEB', 'Ang tagsatagsa kaninyo kinahanglan nga maghinulsol, ug magpabunyag sa ngalan ni Jesu-Cristo aron pasayloon ang inyong mga sala, ug madawat ninyo ang gasa sa Dios nga mao ang Espiritu Santo'),
  ('2 Cor. 13:13', 'CEB', 'Mag-uban unta kaninyong tanan ang grasya sa Ginoong Jesu-Cristo, ang gugma sa Dios, ug ang pagpakig-ambit sa Espiritu Santo'),
  ('1 Ped. 1:2', 'CEB', 'Gipili kamo sumala sa tuyo sa Dios nga Amahan ug gihimong balaang katawhan pinaagi sa iyang Espiritu aron magmasinugtanon kamo kang Jesu-Cristo ug mahinloan sa iyang dugo'),
  ('Jud. 1:20-21', 'CEB', 'Pag-ampo kamo diha sa gahom sa Espiritu Santo, ug pagpabilin kamo sa gugma sa Dios samtang naghulat kamo sa atong Ginoong Jesu-Cristo nga sa iyang kaluoy maghatag kaninyo sa kinabuhing walay kataposan'),
  ('1 Cor. 8:6', 'CEB', 'apan alang kanato may usa lamang ka Dios, ang Amahan nga nagbuhat sa tanang butang'),
  ('Heb. 1:8', 'CEB', 'Apan bahin sa iyang Anak, miingon ang Dios, ‘Ang imong trono, O Dios, molungtad hangtod sa kahangtoran'),
  ('Juan 10:30', 'CEB', 'Ang akong Amahan ug ako usa ra'),
  ('1 Juan 5:7', 'CEB', 'didto sa langit dunay tulo nga nagpamatuod: ang Amahan, ang Pulong ug ang Espiritu. Ug kining tulo usa lamang'),
  ('Heb. 3:4', 'CEB', 'ang Dios maoy nagbuhat sa tanang butang'),
  ('Juan 5:19', 'CEB', 'Ang tanan nga gibuhat sa Amahan gibuhat usab sa Anak'),
  ('Gen. 1:1-2', 'CEB', 'Sa pagsugod pagbuhat sa Dios sa kalibotan ug sa tanang butang sa kalangitan… ang Espiritu sa Dios naglihok ibabaw sa katubigan'),
  ('Sal. 90:2', 'CEB', 'sa wala pa buhata ang kabukiran Dios ka na sukad sa walay sinugdan ug walay kataposan'),
  ('Miq. 5:2', 'CEB', 'sukad sa kakaraanan, sukad sa walay sinugdan ug walay kataposan'),
  ('Sir. 42:18', 'CEB', 'Ang Labing Halangdon nahibalo sa tanang butang nga mahibaloan ug nakasabot sa mga timaan sa katuigan'),
  ('Col. 2:3', 'CEB', 'Diha kaniya natago ang tanang bahandi sa kaalam ug kahibalo sa Dios'),
  ('1 Cor. 2:10', 'CEB', 'Ang Espiritu nagsusi sa tanang mga butang, bisan pa niadtong labing natago nga mga katuyoan sa Dios'),
  ('Jer. 23:24', 'CEB', 'Ako ang Dios nga anaa sa tanang dapit'),
  ('Efeso 4:10', 'CEB', 'Busa siya nga mikunsad mao ra usab ang mikayab saylo pa sa kalangitan, aron mapuno ang tibuok uniberso sa iyang presensya'),
  ('Sal. 139:7-10', 'CEB', 'Asa ba ako paingon aron mahilayo sa imong Espiritu? Asa ba ako motago aron mahilayo sa imong presensya?'),
  ('Sal. 36:9', 'CEB', 'Tinubdan ka sa tanang kinabuhi..'),
  ('Jn. 5:21', 'CEB', 'Kay ingon nga banhawon sa Amahan ang mga patay ug hatagag kinabuhi, banhawon usab sa Anak ug hatagag kinabuhi ang buot niyang banhawon'),
  ('Job. 33:4', 'CEB', 'Ang Espiritu sa Dios maoy nagbuhat kanako ug naghatag kanakog kinabuhi'),
  ('Jer. 10:6', 'CEB', 'Ginoo, wala gayoy sama kanimo. Ikaw makagagahom ug halangdon, gamhanan ang imong ngalan'),
  ('1 Cor. 1:24', 'CEB', 'si Cristo mao ang gahom ug ang kaalam sa Dios'),
  ('Mat. 12:28', 'CEB', 'Dili si Satanas kondili ang Espiritu sa Dios maoy naghatag kanako sa gahom'),
  ('Job. 11:7-8', 'CEB', 'Makatukib ka ba sa mga utlanan sa pagkagamhanan sa Dios? Mas habog pa kini sa langit ug dili mo gayod kini matugkad'),
  ('Rom. 11:33', 'CEB', 'Pagkabahandianon gayod sa Dios ug pagkatulugkaron sa iyang kaalam ug kahibalo! Kinsay makasaysay sa iyang hukom? Kinsay makasabot sa iyang mga paagi?'),
  ('Isa. 9:6', 'CEB', 'Maalamong Magtatambag, Dios nga Gamhanan, Walay Kataposang Amahan, Prinsipe sa Pakigdait'),
  ('Luc. 2:11', 'CEB', 'Kay karong gabhiona, natawo sa lungsod ni David ang inyong Manluluwas, ang Cristo nga Ginoo'),
  ('Isa. 35:4-6', 'CEB', 'Ingna ang nakabsan nag paglaom, ‘Pagmaisog ug ayaw kahadlok! Moanha ang imong Dios aron sa pagpanimalos sa imong mga kaaway.’ Makakita na unya ang buta ug makadungog na ang bungol; magluksolukso na ang bakol daw lagsaw'),
  ('Mat. 11:4-5', 'CEB', 'Pamauli kamo ug suginli si Juan sa inyong nadungog ug nakita: ang mga buta nakakita, ang mga bakol nakalakaw, ang mga sanlahon nangaayo, ang mga bungol nakadungog, ang mga minatay nangabanhaw'),
  ('Isa. 52:12', 'CEB', 'kay mag-una kaninyo ang Ginoo, ug ang Dios sa Israel maoy magbantay sa inyong luyo'),
  ('1 Cor. 10:4', 'CEB', 'kay nanginom man sila gikan sa espirituhanong bato nga nagpaluyo kanila, ug kadtong batoha mao si Cristo'),
  ('Jn. 5:19', 'CEB', 'Ang tanan nga gibuhat sa Amahan, gibuhat usab sa Anak'),
  ('Jn. 8:23', 'CEB', 'Kamo taga dinhi sa yuta, apan ako gikan sa langit'),
  ('Jn. 8:58', 'CEB', 'Sultihan ko kamo: wala pa gani matawo si Abraham, Ako mao na'),
  ('Jn. 10:30', 'CEB', 'Ang akong Amahan ug ako usa ra'),
  ('Jn. 17:5', 'CEB', 'Karon, Amahan, himayaa ako diha sa himaya nga gihuptan ko kauban nimo sa wala pa buhata ang kalibotan'),
  ('Jn. 20:28', 'CEB', 'Ginoo ko ug Dios ko'),
  ('1 Jn. 5:20', 'CEB', 'Ang atong kinabuhi anaa sa matuod nga Dios- sa iyang Anak nga si Jesu-Cristo. Siya ang matuod nga Dios ug ang kinabuhi nga walay kataposan'),
  ('Rom. 9:5', 'CEB', 'Kaliwat sila sa mga patriarka, ug sa ilang kaliwatan natawo si Cristo ang Dios nga labaw sa tanan daygon unta hangtod sa kahangtoran'),
  ('Tito 2:13', 'CEB', 'samtang nagpaabot kita sa bulahang Adlaw nga atong gilaoman inigpadayag na sa himaya sa atong gamhanang Dios ug Manluluwas nga si Jesu-Cristo'),
  ('Fil. 2:6, 10', 'CEB', 'Diha niya kanunay ang kinaiya gayod sa Dios, apan wala siya maghunahuna pagpakigtupong sa Dios pinaagi sa kusog… Busa mangluhod ang tanang binuhat sa langit, sa yuta ug sa ilalom sa yuta; sa pagpasidungog sa ngalan ni Jesus'),
  ('Col. 2:9', 'CEB', 'Kay ang tibuok nga kinaiya sa Dios anaa kang Cristo sa iyang pagkatawo'),
  ('Isa. 45:5', 'CEB', 'Ako mao ang Ginoo, wala nay lain, walay Dios gawas kanako'),
  ('Jn. 17:3', 'CEB', 'Ug kini ang kinabuhing dayon: nga ang mga tawo moila kanimo (Amahan), ang bugtong matuod nga Dios, ug kang Jesu-Cristo nga imong gipadala'),
  ('Num 23:19', 'CEB', 'Ang Dios dili tawo… dili anak sa tawo'),
  ('1 Tim. 2:5', 'CEB', 'Wala nay laing manlalaban taliwala sa Dios ug sa tawo, si Cristo nga tawo'),
  ('Gal. 4:4', 'CEB', 'pag-abot sa hustong panahon gipadala sa Dios ang iyang bugtong anak ug natawo sa tawhanong inahan'),
  ('Num. 23:19', 'CEB', 'Ang Dios dili tawo busa dili siya mamakak. Dili siya anak sa tawo busa dili mausab ang iyang hunahuna'),
  ('Rom. 3:4', 'CEB', 'Magpabilin nga matinud-anon ang Dios bisan pag bakakon ang tanang tawo'),
  ('Jn. 1:1, 14', 'CEB', 'Sa wala pay nagbuhat bisan unsa, ang Pulong diha na. Ang Pulong kauban sa Dios ug ang Pulong Dios… Ang Pulong nahimong tawo ug mipuyo uban kanato'),
  ('Mat. 27:46', 'CEB', 'Dios ko, Dios ko, nganong gibiyaan mo ako'),
  ('Jn. 20:17', 'CEB', 'moadto ako sa akong Amahan ug inyong Amahan, sa akong Dios ug inyong Dios'),
  ('1 Jn. 2:1', 'CEB', 'kita may manlalaban nga si Jesu-Cristo, ang matarong'),
  ('Isa. 59:2', 'CEB', 'ang inyo hinuong kalapasan maoy nag-ulang kaninyo sa inyong Dios; ang inyong mga sala maoy hinungdan sa iyang pagpahilayo kaninyo'),
  ('1 Ped. 2:24', 'CEB', 'Didto sa krus gidala ni Cristo diha sa iyang lawas ang tanan tang mga sala'),
  ('1 Tim. 1:17', 'CEB', 'Alang sa Hari nga walay kataposan, walay kamatayon ug dili makita, ang bugtong Dios'),
  ('Jn. 19:30', 'CEB', 'Unya miduko siya ug namatay'),
  ('1 Ped. 3:18', 'CEB', 'Kay si Cristo mismo namatay sa makausa lamang tungod sa atong mga sala'),
  ('Jn. 11:25', 'CEB', 'Ako ang pagkabanhaw ug ang kinabuhi'),
  ('Jn. 12:34', 'CEB', 'Ang pagtulon-an nga among nadawat mao nga ang Cristo dili mamatay, nga ang Cristo magalungtad'),
  ('Heb. 13:8', 'CEB', 'Si Cristo mao gihapon kagahapon, karon ug sa walay kataposan'),
  ('Mat. 24:36', 'CEB', 'Apan walay nasayod kanus-a moabot kadtong adlawa ug taknaa- bisan ang mga anghel sa langit, ug bisan gani ang Anak, kondili ang Amahan lamang'),
  ('Jn. 16:30', 'CEB', 'Ginoo, nasayod ka sa tanan'),
  ('Deut. 29:29', 'CEB', 'Ang mga butang nga gipadayag iya sa tawo apan ang mga butang nga gitago iya sa Dios'),
  ('Buh. 1:7', 'CEB', 'Ang mga panahon ug mga adlaw gilatid nang daan sa pagbuot sa akong Amahan; dili kamo angay magpakisayod kon kanus-a kini mahitabo'),
  ('1 Kron. 29:11', 'CEB', 'imo man ang tanan nga anaa sa langit ug sa yuta, ingon man ang gingharian ug labaw ikaw sa tanan'),
  ('Jn. 14:28', 'CEB', 'ang Amahan labaw kay kanako'),
  ('Fil 2:6-8', 'CEB', 'Diha niya kanunay ang kinaiya gayod sa Dios, apan wala siya maghunahuna pagpakigtupong sa Dios pinaagi sa kusog. Kondili sa iyang kaugalingong kabubut-on iya kining gibiyaan, ug gisul-ob niya ang kinaiya sa usa ka sulugoon. Natawo siya sama kanato ug nakita siya ingon nga tawo; Nagpaubos siya ug nagmasinugtanon'),
  ('Jn. 16:15', 'CEB', 'Ang tanan nga iya sa Amahan akoa'),
  ('Isa. 43:11', 'CEB', 'Ako mao ang Ginoo, ug walay laing Manluluwas gawas kanako'),
  ('Jn. 12:27', 'CEB', 'Amahan luwasa ako niining taknaa'),
  ('Jn. 4:24', 'CEB', 'Ang Dios espiritu'),
  ('Luc. 24:39', 'CEB', 'Hikapa ako ninyo kay ang espiritu walay unod ug mga bukog ingon sa nakita ninyo kanako'),
  ('Heb. 2:14', 'CEB', 'Sanglit ang mga anak nakaambit man sa unod ug dugo sa mga ginikanan, si Jesus nahimong sama kanila'),
  ('1 Cor. 15:45', 'CEB', 'Ang unang tawo nga si Adan gibuhat nga buhi, apan ang kataposang Adan mao ang Espiritu nga naghatag ug kinabuhi'),
  ('Col 1:15', 'CEB', 'ang panganay sa tanang binuhat'),
  ('Buh. 2:36', 'CEB', 'Busa ang tanang mga tawo sa Israel kinahanglan nga masayod nga kining maong Jesus nga inyong gilansang sa krus gibuhat sa Dios nga Ginoo ug Mesiyas'),
  ('Col. 1:16', 'CEB', 'Kay pinaagi kaniya gibuhat sa Dios ang tanan nga atua sa langit ug ania sa yuta… Gibuhat sa Dios ang tanan pinaagi kaniya ug alang kaniya'),
  ('Heb. 1:2-3', 'CEB', 'Pinaagi kaniya gibuhat sa Dios ang uniberso… Siya maoy nagkupot sa tibuok uniberso pinaagi sa iyang gamhanang pulong'),
  ('Gen. 3:15', 'CEB', 'Ibutang ko ang panag-away taliwala kanimo (sa yawa) ug sa babaye ug taliwala sa imong kaliwat ug sa kaliwat niadto; siya magadugmok sa imong ulo ug ikaw magapahipi sa iyang kiting'),
  ('Luc. 1:28', 'CEB', 'Maghimaya ka puno sa grasya, ang Ginoo uban kanimo, bulahan ka diha sa kababayen-an'),
  ('Rom. 3:23', 'CEB', 'ang tanan nakasala'),
  ('Kin. 1:4', 'CEB', 'ang kaalam dili mopuyo sa lawas nga mahugaw o sa kalag nga ulipon sa sala'),
  ('Exo. 4:12', 'CEB', 'Lakaw kay tabangan ko ikaw pagsulti, ug tudloan ko ikaw sa imong isulti'),
  ('Jer. 1:5', 'CEB', 'Sa wala pa ikaw matawo, gibalaan ko na ikaw tungod kay gipili ko ikaw nga mahimong propeta alang sa akong katawhan'),
  ('Luc. 1:15', 'CEB', 'napuno sa Espiritu Santo sukad sa iyang pagkahimugso'),
  ('Jn. 5:35', 'CEB', 'sama sa suga nga nagsiga'),
  ('Buh. 2:4', 'CEB', 'napuno sa Espiritu Santo ug nakadawat sa daghang mga gasa'),
  ('Buh. 3:15', 'CEB', 'Tinubdan sa Kinabuhi'),
  ('Exo. 3:5', 'CEB', 'Ayaw pagduol, huboa ang imong sandalyas kay balaan ang dapit nga imong gibarogan'),
  ('Exo. 26:34', 'CEB', 'Labing Balaang Dapit'),
  ('Awit 4:7', 'CEB', 'Pagkatahom mo, hinigugma ko, walay buling diha kanimo'),
  ('Awit 4:12', 'CEB', 'Ang akong hinigugmang asawa maoy usa ka tinagoang tanaman nga pinarilan, ug usa ka tubod nga ako ray tag-iya'),
  ('Awit 6:9', 'CEB', 'Bugtong siyang anak ug maoy pinangga sa iyang inahan. Mitan-aw kaniya ang tanang babaye ug misangyaw nga siya mao ang labing bulahan'),
  ('Luc. 1:42', 'CEB', 'Bulahan ka diha sa mga kababayen-an ug bulahan man ang bunga sa imong tiyan'),
  ('Luc. 1:48', 'CEB', 'Ug sukad karon ang tanang kaliwatan motawag kanakog bulahan'),
  ('Heb. 9:22', 'CEB', 'ug walay sala nga gipasaylo gawas kon giulaan kinig dugo'),
  ('1 Ped. 1:19', 'CEB', 'kay giluwas man kamo sa bililhong dugo ni Cristo'),
  ('Job. 14:4', 'CEB', 'Walay butang limpiyo nga mapaabot gikan sa ingon ka dili limpiyo nga tawo'),
  ('Rom. 3:10', 'CEB', 'Nahasulat na, walay usa nga matarong'),
  ('Luc. 1:47', 'CEB', 'Nalipay ang akong kalag tungod sa Dios nga akong Manluluwas'),
  ('Rom. 6:17-18', 'CEB', 'Apan salamat sa Dios nga kamong naulipon kaniadto sa sala, naulipon na karon sa mga pagtulon-an nga nadawat ninyo. Giluwas kamo gikan sa sala ug nangahimo nang mga ulipon sa pagkamatarong'),
  ('Rom. 8:30', 'CEB', 'Busa gitawag sa Dios kadtong iya nang gilain; wala lamang niya tawga sila kondili gihimo usab niyang matarong ug gipaambit sa iyang himaya'),
  ('Rom. 5:12', 'CEB', 'Busa mikaylap ang kamatayon ngadto sa tanang katawhan kay nakasala man ang tanang tawo'),
  ('Luc. 2:35', 'CEB', 'Ug ang kaguol sama sa usa ka hait nga espada molagbas sa imong kaugalingong kasingkasing'),
  ('Mar. 6:3', 'CEB', 'Dili ba siya mao man ang panday nga anak ni Maria, ug igsoon nila ni Santiago, ni Jose, ni Judas, ug ni Simon? Dili ba ang iyang mga igsoong babaye ania man dinhi magpuyo?'),
  ('Mat. 12:46', 'CEB', 'Samtang nakigsulti pa si Jesus sa mga tawo, miabot ang iyang inahan ug mga igsoong lalaki'),
  ('Buh. 1:14', 'CEB', 'nagtigom aron mag-ampo kanunay uban sa mga babaye, ug ni Maria nga inahan ni Jesus, ug sa igsoong lalaki ni Jesus'),
  ('Isa. 7:14', 'CEB', 'Ania karon ang usa ka ulay, manamkon ug manganak og usa ka anak nga lalaki ug ang iyang ngalan pagatawgon og Emmanuel'),
  ('Eze. 44:2', 'CEB', 'Kining pultahana masinirhan na og dili na gyod kini pagaablihan pa, ni may lain pang moagi niining maong pultahan, tungod kay ang Dios sa Israel miaagi man niining pultahana'),
  ('Luc. 1:68', 'CEB', 'Daygon nato ang Ginoo, ang Dios sa Israel! Kay mianhi siya aron pagtabang sa iyang katawhan ug paghatag kanilag kagawasan'),
  ('Gen. 20:17-19', 'CEB', 'ug gisirhan sa Ginoo ang mga pultahan sa banay ni Abimelec'),
  ('Deut. 23:7', 'CEB', 'Ayaw ninyo likayi ang taga-Edumea kay inyo silang igsoon'),
  ('2 Sam. 19:11-12', 'CEB', 'kini sila unod sa akong unod ug bukog sa akong bukog, kini sila akong mga igsoon'),
  ('1 Hari. 9:13', 'CEB', 'Igsoon ko, unsa god kining mga lungsod nga imong gihatag kanako?'),
  ('2 Sam. 1:26', 'CEB', 'Naguol ako pag-ayo kanimo, igsoon kong Jonatan'),
  ('Heb. 2:11', 'CEB', 'Kay sila gibalaan ug ang nagbalaan kanila may usa lamang ka Amahan. Busa dili maulaw si Jesus sa pagtawag kanila nga iyang mga igsoon'),
  ('Mar. 15:40', 'CEB', 'Didto may pipila usab ka babaye nga nagpaantaw sa pagtan-aw. Uban kanila si Salome, si Maria Magdalena, ug si Maria nga inahan sa batan-ong Santiago ug ni Jose'),
  ('Jn. 19:25', 'CEB', 'Duol sa krus ni Jesus nagbarog ang iyang inahan ug ang igsoon sa iyang inahan, si Maria nga asawa ni Cleofas, ug si Maria Magdalena'),
  ('Gen. 8:7', 'CEB', 'Wala mobalik ang uwak hangtod nga mihubas ang tubig'),
  ('1 Sam. 15:35', 'CEB', 'Wala si Samuel makigkita pag-usab kang Saul hangtod nga siya namatay'),
  ('2 Sam. 6:23', 'CEB', 'Wala manganak si Mical hangtod nga siya namatay'),
  ('Num. 3:12', 'CEB', 'gihalad ko nga akong kaugalingon ang panganay nga lalaki sa tagsatagsa ka banay sa Israel ug ang panganay sa tanang mananap'),
  ('Gen. 25:33', 'CEB', 'Busa nanumpa si Esau ug iyang gibaligya ang iyang katungod sa pagka-panganay'),
  ('Zac. 12:10', 'CEB', 'aron inigtan-aw nila kaniya nga ilang gidunggab, magbangotan sila tungod kaniya, sama sa nagbangotan tungod sa kamatayon sa bugtong niyang anak. Ug magpaagas sila ug pait nga luha tungod sa kamatayon sa iyang panganayng anak'),
  ('Mat. 1:25', 'CEB', 'wala hilabti ni Jose si Maria hangtod nga nanganak kang Jesus'),
  ('1 Cor. 8:4', 'CEB', 'Nahibalo kita nga ang diosdios nagrepresentar ug butang nga dili tinuod'),
  ('Isa. 44:17', 'CEB', 'moluhod siya ug mosimba niini; mag-ampo siya niini ug moingon, ‘Luwasa ako kay ikaw may akong dios’'),
  ('1 Hari 11:33', 'CEB', 'Gihimo niya kini kay gisalikway man ni Salome ang Ginoo ug nagsimba siya kang Astarot, ang diosa sa taga-Sidon, kang Camos, ang dios sa Moab, ug kang Moloc, ang dios sa mga Amonihanon'),
  ('Isaias 46:1-2', 'CEB', 'Mao kini ang kataposan sa mga diosdios sa Babilonia. Kaniadto gisimba si Bel ug si Nebo… ang maong mga diosdios wala makaluwas sa ilang kaugalingon'),
  ('1 Sam. 5:7', 'CEB', 'Ug sa pagkasayod sa mga tawo sa Asdod sa nahitabo, miingon sila, ‘Ang Sudlanan sa Kasabotan sa Dios sa Israel kinahanglan ipahilayo kay iya kitang gipaantos ingon man si Dagon nga atong dios’'),
  ('Buh. 7:43', 'CEB', 'Ang inyong gidala mao ang tolda sa diosdios nga si Moloc, ug ang larawan sa bituon sa inyong diosdios nga si Repan; sila mga diosdios nga inyong gibuhat aron simbahon'),
  ('Buh. 14:11-12', 'CEB', 'Sa pagkakita sa mga tawo sa gibuhat ni Pablo, naninggit sila sa ilang pinulongang Licaonianhon, ‘Nanaog ang mga dios sa dagway sa tawo!’ Ug ilang gianggaag Seus si Bernabe ug Herme si Pablo, kay siya man ang tigpamaba'),
  ('Buh. 19:24', 'CEB', 'May usa ka platero nga ginganlag Demetrio nga namuhat ug mga modelong plata sa templo sa diyosa nga si Diana'),
  ('Heb. 9:5', 'CEB', 'Ibabaw sa Sudlanan didto ang mahimayaong mga binuhat nga nagkahulogan sa presensya sa Dios ug gipandong ang mga pako sa mga binuhat sa dapit diin adto pasayloa ang mga sala'),
  ('2 Kron. 3:7, 10', 'CEB', 'Gihal-opan niya ang tibuok Templo ug bulawan-ang mga sagunting, mga bakanan, mga bungbong ug mga pultahan niini, ug gidibuhoan niyag mga kerubin ang mga bungbong'),
  ('Eze. 41:17-20', 'CEB', 'Ang bungbong sa Templo didto sa sulod gikan sa salog hangtod ibabaw sa pultahan gikulitan ug mga larawan sa mga palmira ug sa mga kerubin. Matag kerubin may duha ka nawong: may nawong sa tawo nga nag-atubang sa palmira sa usa ka kilid, ug ang nawong sa usa ka liyon nag-atubang sa palmira sa laing kilid. Gikulit kini sa tibuok palibot sa Templo gikan sa salog ngadto sa ibabaw sa pultahan'),
  ('2 Kron. 7:15-16', 'CEB', 'Bantayan ko kining dapita ug andam ako sa pagpatalinghog sa pag-ampo nga himoon dinhi. Karon gipili ko kining Temploha ingon nga dapit diin simbahon ako hangtod sa hangtod'),
  ('Num 21:8-9', 'CEB', 'Ug giingnan si Moises sa Ginoo, ‘Paghimog bitin nga tumbaga, ug ibutang kini sa tumoy sa usa ka tukon; ug ang hipaakag bitin, kon makakakita niini, dili mamatay.’ Busa nagbuhat si Moises ug bitin nga tumbaga, ug gibutang kini niya sa tumoy sa usa ka tukon; ug kon ang hipaakag bitin motan-aw sa bitin nga tumbaga, dili siya mamatay'),
  ('2 Hari 18:4', 'CEB', 'Gidugmok niya ang halas nga tumbaga nga hinimo ni Moises, kay hangtod niadtong panahona ang katawhan sa Israel nagsunog man ug insenso ingon nga halad niini'),
  ('Lev. 19:30', 'CEB', 'Matngoni ninyo ang akong mga adlawng igpapahulay, ug tahora ninyo ang akong sanctuario'),
  ('2 Kron 3:10-13', 'CEB', 'Ang Dapit nga Labing Balaan gibuhatan niyag duha ka kerubin nga metal ug gihal-opan niyag bulawan… Nagtindog ang mga kerubin nga nag-atubang sa kinadak-ang bahin sa Templo'),
  ('Jos. 7:6', 'CEB', 'Tungod sa kasubo gigisi ni Josue ang iyang bisti ug mihapa sa yuta atubangan Sudlanan sa Kasabotan sa Ginoo. Ang mga pangulo sa Israel mihapa usab didto uban kaniya hangtod sa gabii'),
  ('2 Sam. 6:6-7', 'CEB', 'Ug sa pag-abot nila sa giukanan ni Nacon, gigunitan ni Usa ang Sudlanan sa Kasabotan… ug nasuko ang Ginoo kang Usa. Gipatay siya sa Dios tupad sa Sudlanan sa Kasabotan'),
  ('Sal. 74:4-6', 'CEB', 'Ang mga kaaway mo nagsinggit nga madaogon diha sa imong Templo; giilog nila ang Templo; ilang gipakayab ang kaugalingon nilang bandila. Ingon sila sa mga mamumutol ug kahoy nga namutol pinaagi sa wasay. Ug gilumpag nila pinaagi sa atsa ug martilyo ang kahoy nga may dibuho'),
  ('Kaal. 6:10', 'CEB', 'Kini mga balaang butang, ug kon inyo kining atimanon sa paagi nga balaan, kamo mismo isipon nga balaan'),
  ('Exo. 20:3-5', 'CEB', 'Ayaw pagbaton ug laing dios gawas kanako. Ayaw pagbuhat ug diosdios o larawan sa bisan unsa didto sa langit o dinhi sa yuta, o diha sa tubig nga anaa ilalom sa yuta. Ayaw pagyukbo sa bisan unsang diosdios ni magsimba niini, kay ako ang Ginoo nga inyong Dios ug abughoan ako'),
  ('Deut. 4:16-22', 'CEB', 'Ayaw kamo paghimog mga larawan nga inyong simbahon-larawan sa bisan unsang dagway, sa lalaki o sa babaye'),
  ('Isaias 46:6-7', 'CEB', 'Ang mga tawo mihatag sa ilang plata ug bulawan ug nagsuhol sila g platero aron himoon kining diosdios ug ila kining gisimba. Pas-anon nila kini ug dad-on; itungtong nila kini sa butanganan niini..'),
  ('Sal. 115:4-8', 'CEB', 'Ang ilang mga dios hinimo sa salapi ug bulawan, mga binuhat og tawo. May mga baba sila apan dili makasulti, may mata apan dili makakita. May mga dalunggan apan dili makadungog… Ang nagbuhat ug misalig kanila mahisama unta sa mga diosdios nga ilang gibuhat'),
  ('Buh. 17:29', 'CEB', 'Ug sanglit kita mga anak man sa Dios, dili nato hunahunaon nga ang Dios samag dagway sa larawan nga bulawan, plata o bato nga gikulit pinaagi sa kahanas sa tawo'),
  ('1 Cor. 6:9-10', 'CEB', 'Sa walay duhaduha nasayod kamo nga ang mga daotan dili makasulod sa gingharian sa Dios. Ayaw limbongi ang inyong kaugalingon kay ang mga tawo nga makighilawason, o nagsimba sa mga diosdios… dili makasulod sa gingharian sa Dios'),
  ('Pin. 21:8', 'CEB', 'Apan ang mga talawan, ang mga mabudhion… ang mga nagsimbag diosdios, ug ang tanang mga bakakon mahiagom gayod sa linaw nga kalayo ug asupre nga mao ang ikaduhang kamatayon'),
  ('1 Tim 2:6', 'CEB', 'nga mitugyan sa iyang kaugalingon aron pagluwas sa tanang tawo'),
  ('Fil 1:16', 'CEB', 'ang Dios naghatag kanako sa bulohaton sa pagpanalipod sa ebanghelyo'),
  ('Gal 3:19', 'CEB', 'Ang Balaod gihatag pinaagi sa mga anghel inabagan sa usa ka tawo nga maoy tigpataliwala'),
  ('Sant. 5:16', 'CEB', 'Ang pag-ampo sa tawong matarong dakog kahimoan'),
  ('Num 14:20', 'CEB', 'Gipasaylo ko sila sumala sa imong gihangyo'),
  ('Buh. 27:23-24', 'CEB', 'Ayaw kahadlok, Pablo… ang Dios, sa iyang kaayo moluwas kaninyong tanan tungod kanimo'),
  ('Kaal. 3:2-4', 'CEB', 'Usa ka binoang nga sayop ang panghunahuna nga ang mga matarong nga mga tawo mamatay… daw nag-antos sila sa silot, apan naghupot diay sila sa masaligong paglaom sa pagkawalay kamatayon'),
  ('Mat. 10:28', 'CEB', 'Ayaw kahadloki ang makapatay sa lawas apan dili makapatay sa kalag'),
  ('Pin. 6:9-10', 'CEB', 'ug nakita ko ilalom sa halaran ang mga kalag niadtong gipamatay tungod sa ilang pagsangyaw sa pulong sa Dios… misinggit sila, ‘Ginoo nga Labing Gamhanan, balaan ug matuod!’'),
  ('Sir. 48:13-14', 'CEB', 'Walay butang nga malisod ra kaayo alang kaniya. Bisan sa namatay na siya, ang iyang lawas naghimog milagro. Sa kinabuhi ug sa kamatayon naghimo siya ug katingalahan nga mga milagro'),
  ('Mar. 12:26-27', 'CEB', 'Kay didto nahisulat nga miingon ang Dios kang Moises, ‘Ako ang Dios ni Abraham, ang Dios ni Isaac, ug ang Dios ni Jacob.’ Sa ato pa, siya mao ang Dios sa mga buhi, dili sa mga patay'),
  ('Gen. 48:17-18', 'CEB', 'Panalanginan unta sila sa Dios nga naggiya kanako hangtod karon. Ang anghel nga nagluwas kanako sa tanang katalagman manalangin unta kanila'),
  ('Tob. 12:12', 'CEB', 'Tobit, sa pag-ampo mo ug ni Sara sa Ginoo, ako mao ang nagdala sa inyong mga pag-ampo ngadto sa iyang mahimayaong presensya'),
  ('Pin. 8:3', 'CEB', 'Laing anghel nga may dalang bulawang sudlanan sa insenso miabot ug mibarog atubangan sa halaran. Gihatagan siyag daghang insenso aron idugang sa mga pag-ampo sa tanang katawhan sa Dios ug ihalad didto sa halaran nga diha sa atubangan sa trono'),
  ('Heb. 1:14', 'CEB', 'Busa unsa man diay ang mga anghel? Silang tanan pulos mga espiritu nga nag-alagad sa Dios ug gipadala niya aron pagtabang niadtong maluwas'),
  ('Mat. 22:30', 'CEB', 'mahisama sila sa mga anghel'),
  ('1 Juan 3:2', 'CEB', 'Ang nasayran nato mao nga inigpadayag na ni Cristo mahisama kita kaniya, kay makita man nato siya sa iyang pagkamao gayod'),
  ('1 Cor. 13:12', 'CEB', 'Ang nahibaloan ko karon tipik lamang, apan mahingpit ra unya kini, sama kahingpit sa kahibalo sa Dios bahin kanako'),
  ('Efeso 1:16', 'CEB', 'wala akoy hunong sa pagpasalamat sa Dios tungod kaninyo. Gihinumdoman ko kamo sa akong mga pag-ampo'),
  ('Juan 14:6', 'CEB', 'Ako mao ang dalan, ang kamatuoran ug ang kinabuhi. Walay makaadto sa Amahan kondili pinaagi kanako'),
  ('Buh. 4:12', 'CEB', 'Ang kaluwasan makaplagan diha lamang kaniya, kay wala nay laing ngalan sa tibuok kalibotan nga gihatag sa Dios ngadto sa katawhan nga makaluwas kanato'),
  ('Heb. 7:25', 'CEB', 'Ug busa makahimo siya, karon ug sa gihapon sa pagluwas kanila nga moduol sa Dios pinaagi kaniya, kay buhi man siya hangtod sa kahangtoran aron pagpangaliya sa Dios alang kanila'),
  ('Sal. 115:17', 'CEB', 'Ang mga patay dili na makadayeg sa Ginoo'),
  ('Buh. 10:25', 'CEB', 'Tindog, ayaw akog simbaha kay tawo lamang ako'),
  ('Pin. 22:8-9', 'CEB', 'Ayaw kana buhata! Sulogoon lamang ako sa Dios sama kanimo… Maoy simbaha ang Dios'),
  ('Mat. 4:10', 'CEB', 'Simbaha ang Ginoo nga imong Dios ug siya lamang ang alagari'),
  ('2 Cor. 3:6', 'CEB', 'Kay siya ang naghimo kanamong takos sa pag-alagad sa bag-ong kasabotan nga dili balaod nga sinulat kondili iya sa Espiritu'),
  ('Oseas 14:9', 'CEB', 'Ang maalamon angay nga mosabot sa nahisulat dinhi ug ang masinabuton angay masayod niini'),
  ('Mat. 12:32', 'CEB', 'Ang makasala batok sa Anak sa Tawo mapasaylo, apan ang makasala batok sa Espiritu Santo dili mapasaylo niining kinabuhi o bisan sa sunod nga kinabuhi'),
  ('1 Cor. 3:13-15', 'CEB', 'Sa adlaw ang Ginoo ang buhat sa tagsatagsa ipadayag. Sulayan kini sa kalayo ug sutaon ang iyang matuod nga kalidad. Kon ang iyang buhat hingpit siya makaangkon og ganti, apan kon ang iyang buhat dili hingpit siya mag-antos sa kapildihan apan siya maluwas, wala sapayan nga moagi siya sa kalayo'),
  ('Heb. 12:23', 'CEB', 'sa mga espiritu sa mga matarong nga nahingpit na'),
  ('Isa 30:18', 'CEB', 'Busa maghulat ang Ginoo hangtod nga angay na kamo sa iyang mga kaluoy; ug ikalipay niya ang pagkaluoy kaninyo. Kay ang Ginoo Dios man sa hustisiya'),
  ('Sal. 7:11', 'CEB', 'Ang Dios matarong nga maghuhukom'),
  ('Rom. 2:6', 'CEB', 'Kay gantihan sa Dios ang tagsatgasa sumala sa iyang binuhatan'),
  ('Luc. 12:48', 'CEB', 'apan ang sulugoon nga wala masayod unsa ang gusto sa iyang agalon, ug makabuhat og butang nga tungod niini angay siyang latoson, silotan sa diriyot nga latos'),
  ('Pin. 21:27', 'CEB', 'Apan walay bisan unsa nga hugaw makasulod sa siyudad'),
  ('Isaias 4:4', 'CEB', 'pagalinisan ko sila pinaagi sa espiritu sa kalayo ug sa espiritu sa siga'),
  ('Mat. 5:26', 'CEB', 'Ug timan-i: bilanggoon ka didto hangtod kabayran mo sa hingpit ang imong multa'),
  ('Sant. 2:10', 'CEB', 'Kay ang naglapas bisan sa usa lamang ka sugo sa Balaod nakalapas sa tanan'),
  ('Buh. 10:42', 'CEB', 'siya mao ang gipili sa Dios paghukom sa mga buhi ug sa mga patay'),
  ('1 Ped. 1:18-19', 'CEB', 'nasayran ninyo nga ang gibayad aron sa pagluwas kaninyo sa daotang pagkinabuhi… dili butang nga kawad-an ug bili sama sa salapi o bulawan, kay giluwas man kamo sa bililhong dugo ni Cristo'),
  ('Mat. 16:19', 'CEB', 'Ikaw mao si Pedro ug sa ibabaw niining maong bato pagatukoron ko ang akong Iglesya ug bisan gani ang ganghaan sa hades dili makabuntog niini. Ihatag ko kanimo ang mga yawi sa gingharian sa langit, ang imong gapuson dinhi sa yuta gapuson usab didto sa langit ug ang imong hubaran dinhi sa yuta mahinubaran usab didto sa langit'),
  ('Isa. 22:21-22', 'CEB', 'sul-oban ko siya sa imong bisti, ug baksan ko siya sa imong bakos, ug itugyan ko kaniya ang imong gahom; mahimo siyang pangulo sa mga molupyo sa Jerusalem ug sa Juda. Ug ihatag ko kaniya ang mga yawi sa balay ni David; siyay moabli niini ug walay makasira; mosira niini ug walay makaabli'),
  ('1 Ped. 5:1', 'CEB', 'Naghangyo ako sa mga pangulo diha sa inyong iglesia, ingon nga ako pangulo usab sama kaninyo'),
  ('Col. 1:18', 'CEB', 'si Cristo ang ulo sa Iglesya nga mao ang iyang lawas'),
  ('Prob. 10:12', 'CEB', 'ang gugma mopasaylo sa tanang kalapasan'),
  ('1 Ped. 4:8', 'CEB', 'Labaw sa tanan, paghigugmaay kamo sa kinasingkasing gayod, kay ang gugma nagtabon sa daghang mga sala'),
  ('Efeso 1:7', 'CEB', 'Kay naluwas kita tungod sa kamatayon ni Cristo, sa ato pa, napasaylo na ang atong mga sala'),
  ('Col. 2:14', 'CEB', 'Gipapas niya ang tanan tang mga utang lakip ang mga kasabotan bahin niini ug giwagtang niya ang tanan pinaagi sa paglansang niini didto sa krus'),
  ('Rom. 2:8', 'CEB', 'Apan ipahamtang sa Dios ang iyang kasuko ug kapungot sa mga tawo nga naghunahuna sa ilang kaugalingon ug nagsalikway sa kamatuoran aron pagbuhat sa daotan'),
  ('Jn. 20:23', 'CEB', 'Kon pasayloon ninyo ang mga sala sa mga tawo, gipasaylo kini; kon ang ilang mga sala dili ninyo pasayloon, dili usab kini pasayloon'),
  ('Num. 12:14', 'CEB', 'Pagawasa siya sa kampo sulod sa pito ka adlaw ug pagkatapos niana mahimo na nga pasudlon siya'),
  ('Num. 14:20-21', 'CEB', 'Gipasaylo ko sila sumala sa imong gihangyo. Apan sa pagkatinuod, samtang buhi ako, ug ang tibuok kalibotan mapuno sa himaya sa Ginoo, walay mabuhi niining mga tawhana nga makasulod niadtong yutaa'),
  ('Num. 20:12', 'CEB', 'Kay wala man ako tuohi ninyo, aron balaanon ako sa mga tawo sa Israel, dili kamo maoy mangulo sa mga tawo ngadto sa yuta nga akong ihatag kanila'),
  ('2 Sam. 12:13-14', 'CEB', 'Gipasaylo sa Ginoo ang imong sala ug dili ka niya patyon. Apan kay pinaagi niining buhata imo mang gipasipad-an ang Ginoo, mamatay ang bata nga matawo kanimo'),
  ('Mat. 18:18', 'CEB', 'ang inyong idili dinhi sa yuta idili usab didto sa langit; ug ang inyong itugot dinhi sa yuta, itugot usab didto sa langit'),
  ('Rom. 5:15', 'CEB', 'kay kon daghan ang nangamatay tungod sa pagpakasala sa usa ka tawo, labi pang dako ang grasya ug ang gasa sa Dios nga mabatonan sa daghang mga tawo pinaagi sa usa ka tawo nga mao si Jesu-Cristo'),
  ('Col. 1:24', 'CEB', 'Kay pinaagi sa akong mga giantos nakatabang ako paghingpit sa wala pa matapos nga mga pag-antos ni Cristo alang sa iyang lawas nga mao ang iglesia'),
  ('Rom. 12:4-5', 'CEB', 'Daghan ug mga bahin ang atong lawas, ug ang matag bahin niini may kaugalingong bulohaton. Kita usab, bisan daghan, usa lamang ka lawas nga nahiusa kang Cristo, ug nalambigit kita sa usag-usa ingon nga nagkalainlaing bahin sa usa ka lawas'),
  ('1 Cor. 12:25-26', 'CEB', 'Busa walay pagkabahinbahin sa lawas, kondili ang tanang bahin may samang pagtagad sa usag-usa. Kon ang usa ka bahin sa lawas mag-antos, ang ubang bahin mag-antos usab; kon daygon ang usa ka bahin, ang tanang bahin makaambit sa kalipay'),
  ('Jn. 15:5', 'CEB', 'Kon wala ako, wala kamoy mahimo'),
  ('Mat. 18:17', 'CEB', 'Ug kon dili siya mamati sa iglesya, isipa siya nga usa ka langyaw o kobrador sa buhis'),
  ('Mat. 7:7', 'CEB', 'pangayo kamo, ug kamo hatagan'),
  ('Buh. 16:4', 'CEB', 'Sa ilang pag-agi sa mga kalungsoran ilang gitugyan ngadto sa mga magtutuo ang mga lagda nga gikauyonan sa mga apostoles ug sa mga pangulo sa iglesia sa Jerusalem, ug gipahimangnoan sila sa pagtuman niini'),
  ('Heb. 12:11', 'CEB', 'Kon kastigohon kita, makasubo kini kanato inay makalipay. Apan sa kaulahian kadtong nakadawat sa maong pagpanton makaani sa kinabuhing matarong ug ganting malinawon'),
  ('Col. 2:16-17', 'CEB', 'Busa ayaw ninyo itugot nga may magsaway kaninyo sa inyong kan-on o imnon, o bahin sa mga adlaw nga balaan, o sa pangilin sa bag-ong bulan… Kining tanan mga landong lamang sa mga butang nga umaabot, apan ang katumanan mao si Cristo'),
  ('Fil 1:29', 'CEB', 'Kay gihatagan kamo sa pribilihiyo, dili lamang sa pagtuo kang Cristo, kondili sa pagpasakit usab tungod kaniya'),
  ('1 Tim. 2:4', 'CEB', 'kay kabubut-on sa Dios nga ang tanang tawo maluwas ug mahibalo sa kamatuoran'),
  ('Mat. 18:14', 'CEB', 'ang inyong Amahan nga atua sa langit dili buot nga may mawala bisag usa niining mga gagmayng bata'),
  ('Jn. 3:3', 'CEB', 'Walay makakita sa gingharian sa Dios gawas kon siya matawo pag-usab'),
  ('Jn. 3:5', 'CEB', 'Sultihan ko ikaw: walay makasulod sa gingharian sa Dios gawas kon matawo siya pinaagi sa tubig ug sa Espiritu'),
  ('Jn. 3:6', 'CEB', 'Ang gianak sa tawo, tawo usab; ug ang gianak sa Espiritu, espiritu usab'),
  ('1 Ped. 3:20-21', 'CEB', 'Walo lamang ka tawo ang misulod sa arka ug naluwas sa tubig nga naghulagway sa bunyag nga karon nagluwas kaninyo'),
  ('Tito 3:5', 'CEB', 'kita iyang giluwas, dili tungod sa bisan unsang maayo nga atong nabuhat, kondili tungod sa iyang kaluoy pinaagi sa paghugas nga gihimo sa Espiritu Santo aron kita makabaton ug bag-ong kinabuhi'),
  ('Sal. 51:5', 'CEB', 'Daotan ako sukad ako mahimugso; ug makasasala sukad ako ipanamkon'),
  ('Gal. 3:27', 'CEB', 'Gibunyagan kamo aron mahiusa kang Cristo, ug busa nakaambit na kamo sa kinaiya ni Cristo'),
  ('Mar. 10:14', 'CEB', 'kay ang Gingharian sa Dios ila sa sama niining mga bataa'),
  ('Mar. 16:15-16', 'CEB', 'Isangyaw kining Maayong Balita… Ang motuo ug magpabunyag maluwas'),
  ('Mat. 18:6', 'CEB', 'Ug mahitungod niining gagmayng mga bata nga nagtuo kanako'),
  ('Mat. 21:16', 'CEB', 'Ang mga bata ug ang mga masuso gibansay mo sa paghalad ug hingpit nga pagdayeg kanimo'),
  ('Buh. 2:39', 'CEB', 'Kay saad sa Dios alang man kaninyo ug sa inyong mga anak'),
  ('Luc. 3:16', 'CEB', 'Nagbunyag ako kaninyo pinaagi sa tubig, apan may moabot nga mas labaw pa kay kanako… Magbunyag siya kaninyo pinaagi sa Espiritu Santo ug sa kalayo'),
  ('Eze. 18:20', 'CEB', 'Ang anak dili mag-antos sa sala sa iyang amahan'),
  ('Lam. 5:7', 'CEB', 'Nakasala ang among katigulangan ug nangamatay sila; ug kami ang nag-antos sa silot sa ilang mga sala'),
  ('Buh. 10:48', 'CEB', 'Busa misugo siya nga bunyagan sila sa ngalan ni Jesu-Cristo'),
  ('Buh. 3:6', 'CEB', 'Ug si Pedro miingon, walay akoy salapi o bulawan, apan hatagan ko ikaw niining ania kanako: sa ngalan ni Jesu-Cristo nga Nazaretnon, lakaw'),
  ('Buh. 4:7', 'CEB', 'Unsa bang gahoma ang anaa kaninyo, ug kinsa mang ngalan ang gigamit ninyo?'),
  ('Rom. 6:4', 'CEB', 'Tungod niini, sa pagbunyag kanato gilubong kita uban kaniya…'),
  ('Mat. 1:21', 'CEB', 'nganli siyag Jesus- kay luwason niya ang iyang katawhan sa ilang mga sala'),
  ('Mar. 2:5', 'CEB', 'Anak, gipasaylo na ang imong mga sala'),
  ('Jn. 20:22-23', 'CEB', 'Dawata ninyo ang Espiritu Santo. Kon pasayloon ninyo ang mga sala sa mga tawo, gipasaylo kini; kon ang ilang mga sala dili ninyo pasayloon, dili usab kini pasayloon'),
  ('Num. 5:7', 'CEB', 'Magsugid sila sa ilang mga sala nga nahimo'),
  ('Jos. 7:19', 'CEB', 'Anak ko, isugid ang kamatuoran dinhi sa atubangan sa Ginoo… ug tug-ani ako sa gibuhat mo. Ayaw kini itago gikan kanako'),
  ('1 Sam. 15:24-25', 'CEB', 'Nakasala ako kay gilapas ko man ang imong mga pulong… Busa karon hangyoon ko ikaw nga imo akong pasayloon'),
  ('Eccl. 5:6', 'CEB', 'Ayaw itugot nga ang imong mga pulong makaangin kanimo sa pagpakasala; busa isugid sa pari sa Dios nga dili mo tuyo ang pagbuhat sa ingon'),
  ('Mat. 3:6', 'CEB', 'Gisugid nila ang ilang mga sala..'),
  ('Buh. 19:18', 'CEB', 'Daghang mga magtutuo nangabot ug sa dayag misugid nga nagsalamangka sila kaniadto'),
  ('2 Cor. 13:5', 'CEB', 'Susiha ug hukmi ang inyong kaugalingon aron pagtino kon nagpadayon ba kamo sa pagtuo'),
  ('2 Cor. 7:10', 'CEB', 'Kay ang kasubo nga gikan sa Dios makapahinulsol ug makatultol kaninyo ngadto sa kaluwasan'),
  ('Prob. 28:13', 'CEB', 'Kadtong nagatabon sa iyang sala dili mouswag apan kadtong nagasugid sa iyang mga sala makadawat og kaluoy'),
  ('Prob. 14:16', 'CEB', 'Ang maalamon maglikay sa peligro apan ang buangbuang magpaduol hinuon niini'),
  ('Joel 2:12', 'CEB', 'Apan bisan karon, paghinulsol kamo sa kinasingkasing ug balik kanako nga magpuasa, maghilak ug magbangotan'),
  ('Esd. 10:11', 'CEB', 'Busa isugid ang inyong mga sala ngadto sa Ginoo'),
  ('Sal. 32:5', 'CEB', 'Gisugid ko kini sa Ginoo ug gipasaylo niya ang tanan kong kalapasan'),
  ('Sal. 69:5', 'CEB', 'kay ang tanan natong kasal-anan wala matago gikan kaniya'),
  ('1 Jn. 1:9', 'CEB', 'Apan kon isugid nato sa Dios ang atong mga sala, tumanon niya ang iyang mga saad ug buhaton ang matarong ug mopasaylo gayod sa tanan tang mga sala ug maghinlo sa tanan tang mga kalapasan'),
  ('Mat. 11:28', 'CEB', 'Umari kamo kanako, kamong tanan nga gikapuyan'),
  ('Mar. 2:7', 'CEB', 'Walay tawo nga makapasaylog sala, kondili ang Dios lamang'),
  ('2 Cor. 5:18', 'CEB', 'si Cristo naghatag kanamo niining bulohaton sa pagpasig-uli'),
  ('Mat. 7:4', 'CEB', 'Unsaon mo man pag-ingon sa imong isigkatawo, ‘Abi, kuhaon ko kanang imong puling,’ nga naa may troso sa imong mata?'),
  ('Mat. 18:35', 'CEB', 'pagpinasayloay kamo aron pasayloon kamo sa inyong Amahan nga atua sa langit'),
  ('Luc. 22:15', 'CEB', 'Dako kaayo ang akong tinguha sa pagkaon uban kaninyo niining panihapon sa Pangilin sa Pagsaylo sa dili pa ako mag-antos'),
  ('Mat. 26:26-28', 'CEB', 'Imna kini ninyong tanan, kini mao ang akong dugo nga naglig-on sa kasabotan, ang akong dugo nga giula alang sa tanang mga tawo aron ang mga sala mapasaylo'),
  ('Jn. 6:56', 'CEB', 'Ang mokaon sa akong unod ug moinom sa akong dugo magpuyo dinhi kanako ug ako diha kaniya'),
  ('Jn. 6:57', 'CEB', 'ang mokaon kanako mabuhi tungod kanako'),
  ('Jn. 6:54', 'CEB', 'Ang mokaon sa akong unod ug moinom sa akong dugo may kinabuhing walay kataposan ug banhawon ko siya sa kataposang adlaw'),
  ('1 Cor. 11:27', 'CEB', 'Busa ang mokaon sa pan sa Ginoo ug moinom sa iyang kupa sa paagi nga dili takos, nakasala batok sa lawas ug sa dugo sa Ginoo'),
  ('1 Cor.10:16', 'CEB', 'Ang kupa sa panalangin nga tungod niini gipasalamatan nato ang Dios-dili ba kini pakig-ambit man nato sa dugo ni Cristo inig-inom nato gikan niining kupa? Ug dili ba pakig-ambit man nato sa lawas ni Cristo inigkaon nato niining pan nga atong gipikaspikas?'),
  ('Exo. 19:6', 'CEB', 'Mahimo kamong usa ka nasod nga mag-alagad kanako ingon nga pari'),
  ('1 Ped. 2:5', 'CEB', 'Panuol kamo ingon nga mga batong buhi ug ipagamit ang inyong kaugalingon aron pagtukod sa espirituhanong templo diin mag-alagad kamo ingon nga balaang mga pari nga maghalad sa espirituhanon ug makapahimuot nga mga halad ngadto sa Dios pinaagi kang Jesu-Cristo'),
  ('Buh. 6:3-6', 'CEB', 'gidala ngadto sa mga apostoles, ug ang mga apostoles nag-ampo ug nagpandong kanila sa ilang mga kamot'),
  ('Buh. 13:3', 'CEB', 'nagpuasa ug nag-ampo ug gipandongan nila sa ilang mga kamot si Bernabe ug si Saulo ug unya gipalakaw sila'),
  ('2 Tim. 1:6', 'CEB', 'Tungod niini, pahinumdoman ko ikaw sa paggamit sa gasa nga gihatag sa Dios kanimo sa dihang gipandongan ko ikaw sa akong mga kamot'),
  ('1 Tim. 5:22', 'CEB', 'Ayaw ipandong pagdalidali ang imong mga kamot kang bisan kinsa alang sa buluhaton sa Ginoo'),
  ('Rom. 15:16', 'CEB', 'sa akong pagka-sulugoon ni Cristo Jesus sa pag-alagad sa mga dili judio. Nag-alagad ako ingon nga pari aron pagwali sa Maayong Balita nga gikan sa Dios'),
  ('Tito 1:5', 'CEB', 'aron magtudlo kag mga pari sa matag lungsod'),
  ('1 Tim. 4:1-3', 'CEB', 'nagpatalinghog sa pagtulon-an o doctrina sa yawa nga nagpugong sa pagpangasawa ug naglikay sa pagkaog karne'),
  ('Luc. 22:19', 'CEB', 'Mao kini ang akong lawas nga gitugyan alang kaninyo… Kining kupa mao ang Bag-ong Kasabotan sa Dios, tiniman-an sa akong dugo nga giula alang kaninyo'),
  ('Rom. 12:1', 'CEB', 'hangyoon ko kamo sa pagtugyan sa inyong kaugalingon ngadto sa Dios, ingon nga buhing halad'),
  ('Heb. 10:4', 'CEB', 'kay ang dugo sa mga toro nga baka ug mga kanding dili gayod makawagtang sa mga sala'),
  ('Heb. 10:11', 'CEB', 'Ang matag pari nga Judio nagtuman sa iyang pag-alagad adlaw-adlaw ug nagsubli-subli paghalad sa samang mga sakripisyo. Apan kining mga sakripisyoha dili gayod makawagtang sa mga sala'),
  ('Gen. 14:18', 'CEB', 'Si Melquisedec nga hari sa Salem ug pari usab sa Labing Halangdong Dios nagdalag pan ug bino'),
  ('Mal. 1:11', 'CEB', 'tungod kay ang usa ka hingpit nga halad igahalad sa akong ngalan'),
  ('Buh. 2:46', 'CEB', 'Nagpadayon sila pagtigom kada adlaw didto sa templo, ug naghiusa sila sa pagpangaon uban ang masaya ug nangabusog ang ilang mga kasingkasing'),
  ('Buh. 20:7', 'CEB', 'Pagka-Domingo sa gabii nagtigom kami aron pag-ambit sa balaang panihapon'),
  ('1 Cor. 10:16', 'CEB', 'Ang kupa sa panalangin nga tungod niini gipasalamatan nato ang Dios- dili ba kini pagkig-ambit man nato sa dugo ni Cristo inig-inom nato gikan niining kupa? Ug dili ba pagkig-ambit man nato sa lawas ni Cristo inigkaon nato niining pan nga atong gipikaspikas'),
  ('Jn. 6:58', 'CEB', 'Ang mokaon nining maong pan mabuhi sa dayon'),
  ('2 Ped. 3:8', 'CEB', 'ayaw ninyo hikalimti nga sa Ginoo ang usa ka adlaw ingon sa 1,000 ka tuig ug ang 1,000 ka tuig ingon lamang sa usa ka adlaw'),
  ('Isa. 40:28', 'CEB', 'Wala ka ba diay mahibalo ni makadungog nga ang Ginoong Dios nga walay kataposan maoy nagbuhat sa tibuok kalibotan? Dili siya maluya ni kapuyan, ug dili matukib ang iyang kahibalo'),
  ('Neh. 9:14', 'CEB', 'ug gisugo mo sila sa pagtamod sa Adlawng Igpapahulay. Pinaagi sa imong alagad nga si Moises, gihatagan mo sila sa imong mga balaod'),
  ('Deut. 5:15', 'CEB', 'Hinumdomi ninyo nga mga ulipon usab kamo didto sa Ehipto, ug gipagawas kamo sa Ginoo nga inyong Dios pinaagi sa iyang dakong gahom; busa gisugo kamo sa Ginoo nga inyong Dios sa pagtamod sa Adlawng Igpapahulay'),
  ('Oseas 2:11', 'CEB', 'Ug hunongon ko ang tanan niyang kalipay, ang iyang mga pangilin, mga bag-ong subang sa bulan, mga Adlawng Igpapahulay, ug ang tanang gitagal niya nga mga pangilin'),
  ('Neh. 13:18', 'CEB', 'Apan gipasipad-an gihapon ninyo ang Adlawng sa Igpapahulay ug sa ingon naghagit kamo sa dugang pang kasuko sa Dios batok sa Israel'),
  ('Eze. 20:13', 'CEB', 'Apan ang tibuok katawhan sa Israel misukol kanako didto sa kamingawan. Wala nila tumana ang akong mga sugo… Gipasipad-an nila pag-ayo ang akong mga Adlawng Igpapahulay'),
  ('Lam. 2:7', 'CEB', 'Gigun-ob niya ang Templo diin ato siyang gisimba ug gipahunong ang pagsaulog sa balaang mga adlaw ug mga Adlawng Igpapahulay'),
  ('Jer. 17:21', 'CEB', 'kinahanglan nga dili sila magdalag bisag unsa sa Adlawng Igpapahulay'),
  ('Jn. 5:18', 'CEB', 'Tungod niini misamot hinuon ang tinguha sa kadagkoan sa mga Judio sa pagpatay kaniya, sanglit dili lamang kay gilapas niya ang balaod sa Adlawng Igpapahulay, kondili miingon pa gayod siya nga ang Dios iyang Amahan'),
  ('Heb. 4:8-9', 'CEB', 'Kay kon si Josue nakahatag pa kanilag pahulay, dili na unta ang Dios maghisgot pa ug laing adlaw. Busa duna pay adlaw sa pahulay alang sa katawhan sa Dios'),
  ('1 Cor. 15:14', 'CEB', 'ug kon wala banhawa si Cristo, kawang lamang ang among giwali ug kawang usab ang inyong pagtuo'),
  ('1 Cor. 16:2', 'CEB', 'Sa unang adlaw sa matag semana, ang usag-usa kaninyo kinahanglan maagahin ug kuwarta sumala sa inyong kinitaan, ug tigomon kini'),
  ('Pin. 22:5', 'CEB', 'Didto wala nay gabii ug dili na sila magkinahanglan ug mga suga o kahayag sa adlaw, kay ang Ginoong Dios mao may ilang kahayag'),
  ('Mat. 5:17', 'CEB', 'Ayaw ninyo hunahunaa nga mianhi ako aron pagsalikway sa Balaod ni Moises ug sa mga propeta. Wala ako moanhi aron pagsalikway niini, kondili aron paghatag niini sa hustong kahulogan'),
  ('Luc. 4:16', 'CEB', 'ingon sa naandan miadto siya sa sinagoga sa Adlaw nga Igpapahulay'),
  ('Mat. 24:20', 'CEB', 'Busa pag-ampo kamo sa Dios nga dili unta kamo pakagiwon sa panahon sa tingtugnaw o sa Adlaw nga Igpapahulay'),
  ('1 Tim. 4:4-5', 'CEB', 'Maayo ang tanang gibuhat sa Dios; ang tanan angay nga dawaton uban ang pagpasalamat, ug walay isalikway bisan unsa, kay ang pulong sa Dios ug ang pag-ampo maoy nakapabalaan niini'),
  ('Gen. 9:3-4', 'CEB', 'Makakaon kamo sa tanang mananap ug sa lunhawng mga tanom kay gitugyan ko kini kaninyo aron mahimong pagkaon ninyo. Usa lamang ka butang nga kinahanglan dili ninyo kan-on, ug kini mao ang karne nga may dugo pa kay ang kinabuhi anaa man sa dugo'),
  ('Lev. 11:1-31', 'CEB', 'Apan ayaw ninyo kan-a ang kamelyo, ang koneho o ang liebre. Kinahanglan nga isipon nga hugaw kining mga mananapa… Ang baboy bisan tuod kon pikas ang kuko niini, dili man kini mousap, busa hugaw kini alang kaninyo… apan bisan unsa nga anaa sa kadagatan ug sa mga suba ug sa katubigan nga walay mga kapay ug mga himbis dili angayng kan-on'),
  ('Lev. 10:10', 'CEB', 'Ilhon ninyo ang kalainan sa balaan ug sa dili balaan, ug ang kalainan sa hugaw ug sa hinlo'),
  ('Lev. 17:11', 'CEB', 'kay ang kinabuhi anaa sa dugo, ug gihatag ko kini kaninyo aron gamiton sa pagpapas sa sala'),
  ('Buh. 15:29', 'CEB', 'Ayaw kamo pagkaon sa kalan-on nga gihalad ngadto sa mga diosdios, ni dugo, ni mananap nga gituok'),
  ('Lev. 10:18', 'CEB', 'Ug sanglit ang dugo niini wala man dad-a sulod sa sanctuario, inyo unta kining gikaon didto sa sanctuario sumala sa akong sugo'),
  ('1 Sam. 14:32, 41', 'CEB', 'Nag-ilogay ang mga tawo sa mga butang nga gipamiyaan sa mga kaaway, ug nanakop silag mga karnero ug mga baka, ug ilang giihaw kini ug ilang gikaon lakip ang dugo… Kon ako ang nakasala o si Jonatan, ipakita ang Urim, apan kon ang nakasala mao ang katawhan sa Israel, ang Tumim maoy ipakita. Apan ang natungnan sa ripa mao si Jonatan ug si Saul'),
  ('Mar. 7:18-19', 'CEB', 'Bisan unsa nga mosulod sa baba sa tawo dili makapahugaw kaniya, kay kini dili man mosulod sa iyang kasingkasing, kondili ngadto sa iyang tiyan, ug unya mogula usab sa lawas. Sa pagsulti ni Jesus niini, iyang gipahayag nga mahimong kan-on ang tanang pagkaon'),
  ('Luc. 10:8', 'CEB', 'kaon kamo sa tanan nga idulot kaninyo'),
  ('Buh. 11:5-9', 'CEB', 'Ayaw isipa nga mahugaw ang giila sa Dios nga malinis'),
  ('Buh. 15:19-20', 'CEB', 'Ang akong hunahuna mao nga dili nato samokon ang mga dili Judio nga midawat sa Dios. Hinunoa, ato silang sulatan nga dili sila mangaon sa mahugaw nga mga kalan-on tungod kay kini gihalad man ngadto sa mga diosdios… ug nga dili sila mangaon sa bisan unsang mananap nga gituok, ug sa bisan unsang dugo'),
  ('Rom. 14:3', 'CEB', 'Ang mokaon bisag unsa dili angay nga maghukom sa tawo nga utanon ray kan-on; ug ang tawo usab nga utanon ray kan-on, dili angay maghukom sa tawo nga mokaon bisag unsa, kay gidawat na siya sa Dios'),
  ('Rom. 14:14', 'CEB', 'Apan kon may nagtuo nga hugaw ang usa ka butang, hugaw kini alang kaniya'),
  ('Rom. 14:17', 'CEB', 'Kay ang Gingharian sa Dios dili pagkaon ug pag-inom, kondili pagkamatarong, pakigdait, ug kalipay nga gihatag sa Espiritu Santo'),
  ('1 Cor. 8:8', 'CEB', 'Hinuon, ang pagkaon dili makapaduol kanato sa Dios ni makadaot kanato kon dili kita mokaon, ni makaayo kanato kon mokaon kita niini'),
  ('1 Cor. 10:25, 31', 'CEB', 'Makahimo kamo pagkaon bisan unsang karne nga gibaligya diha sa merkado, sa walay pag-agad sa inyong konsensya… Busa kon mokaon kamo o moinom kamo o magbuhat bisan unsa, buhata ang tanan sa pagpasidungog sa Dios'),
  ('Heb. 13:9', 'CEB', 'Ayaw itugot nga ang lahi nga mga pagtulon-an makapatipas kaninyo gikan sa matarong agianan. Maayo gayod nga malig-on ang atong kalag pinaagi sa grasya sa Dios, ug dili pinaagi sa mga tulomanon mahitungod sa kalan-on kay wala makatabang ang maong tulomanon niadtong nagtuman niini'),
  ('Gal. 3:13', 'CEB', 'tinunglo ang gibitay sa kahoy'),
  ('Pin 13:16', 'CEB', 'Gipugos sa mananap nga mapatikan ang tanang tawo, inila og dili inila, dato ug kabos, ulipon ug dili ulipon, diha sa tuo nilang kamot ug agtang'),
  ('Gal. 3:14', 'CEB', 'Gihimo kini ni Cristo (ang pagpalansang sa krus) aron ang panalangin nga gisaad sa Dios ngadto kang Abraham ikahatag ngadto sa mga dili judio pinaagi kang Cristo Jesus, aron kita makadawat sa Espiritu nga gisaad sa Dios pinaagi sa pagtuo'),
  ('1 Cor. 1:18', 'CEB', 'alang niadtong nangawala ang kaasuyan sa krus binuang, apan alang kanatong linuwas kini gahom ug kaalam sa Dios'),
  ('Mat. 16:24', 'CEB', 'Kon buot kamong mosunod kanako, pas-ana ninyo ang inyong krus matag adlaw ug sunod kanako'),
  ('Fil. 3:18', 'CEB', 'dunay daghang mga magtutuo kansang pagkinabuhi sukwahi sa tuyo sa kamatayon ni Cristo sa krus'),
  ('Gal. 5:24', 'CEB', 'Ang mga tawhanong kailibgon ug mga pangandoy gilansang na sa krus sa mga tawo nga iya na ni Cristo Jesus'),
  ('Gal. 6:14, 17', 'CEB', 'Apan alang kanako magpasigarbo lamang ako sa krus sa atong Ginoong Jesu-Cristo kay pinaagi sa iyang krus patay na ang kalibotan alang kanako, ug ako patay na alang sa kalibotan… manghinaot ako nga wala na untay magsamok kanako kay ang mga ulat nga ania sa akong lawas nagmatuod nga ulipon ako ni Jesus'),
  ('Deut. 6:6-9', 'CEB', 'Itudlo kini sa inyong kabataan. Hisgoti kini kon anaa kamo sa inyong balay, o magpanaw kamo, o sa dayon na ninyong katulog ug sa pagmata ninyo sa buntag. Ibugkos kini sa inyong kamot ingon nga ilhanan ug ibutang ingon nga timaan diha sa inyong agtang. Isulat kini diha sa haligi sa pultahan sa inyong balay ug diha sa inyong mga ganghaan'),
  ('Eze. 9:5-6', 'CEB', 'Sulod kamo kaniya ug pamatya ninyo sa walay kukaluoy ang mga molupyo sa siyudad. Pamatya ang mga tigulang ug ang mga batan-on ingon man ang kabataan ug kababayen-an, apan ayaw ilakip pagpatay kadtong may patik (tau = krus) sa ilang agtang'),
  ('Luc. 11:44', 'CEB', 'Sama kamo sa lubong nga walay timaan, nga wala lamang hibaloi sa mga tawo nga ila diayng gitamakan'),
  ('Pin. 14:1', 'CEB', 'kansang mga agtang gisulatan sa iyang ngalan ug sa ngalan sa iyang Amahan'),
  ('Pin. 22:4', 'CEB', 'Makakita sila sa nawong niya ug ang iyang ngalan isulat diha sa ilang agtang'),
  ('Efeso 1:13', 'CEB', 'Busa gipatikan kamo sa Dios pinaagi sa paghatag kaninyo sa Espiritu Santo'),
  ('Efeso 4:30', 'CEB', 'kay ang Espiritu mao ang patik sa Dios diha kaninyo ilhanan nga kamo iya na, ug garantiya nga moabot ang adlaw nga luwason kamo sa Dios'),
  ('Pin 13:17', 'CEB', 'Walay makapamalit ug makapamaligya gawas niadtong may patik sa ngalan sa mananap'),
  ('Sal. 99:5', 'CEB', 'Dayga ninyo ang Dios ug simbaha ang iyang tumbanan kay kini balaan'),
  ('Jn. 3:16', 'CEB', 'Kay gihigugma pag-ayo sa Dios ang kalibotan ug tungod niini gihatag niya ang iyang bugtong Anak, aron ang tanan nga motuo kaniya dili mamatay, kondili makabaton hinuon sa kinabuhing dayon'),
  ('Jn. 1:12', 'CEB', 'Hinuon, may midawat ug mituo kaniya; busa sila gihatagan niya sa katungod nga mahimong mga anak sa Dios'),
  ('Rom. 10:13', 'CEB', 'Ang tanan nga magsangpit sa ngalan sa Ginoo maluwas'),
  ('Efeso 2:8-9', 'CEB', 'Kay pinaagi sa pagtuo naluwas kamo tungod sa grasya sa Dios. Dili kini inyong buhat kondili gasa sa Dios. Busa walay makapasigarbo niini sanglit dili man kini bunga sa inyong mga paningkamot'),
  ('1 Jn. 5:13', 'CEB', 'Gisulatan ko kamo niini aron kamong tanan nga nagtuo sa ngalan sa Anak sa Dios masayod nga kamo may kinabuhing walay kataposan'),
  ('Heb. 11:6', 'CEB', 'Walay makapahimuot sa Dios kon walay pagtuo'),
  ('Sant. 2:14, 24, 26', 'CEB', 'Mga igsoon, unsay kapuslanan kon ang usa ka tawo moingon nga siya may pagtuo apan wala siyay mga maayong buhat? Makaluwas ba kaniya ang iyang pagtuo? Dili gayod!… nakita ninyo nga ang usa ka tawo isipon sa Dios nga matarong tungod sa iyang mga buhat, ug dili tungod sa pagtuo lamang… Kay ingon nga patay ang lawas nga wala nay espiritu, patay usab ang pagtuo kon walay mga buhat'),
  ('Rom. 2:6-7', 'CEB', 'Kay gantihan sa Dios ang tagsatagsa sumala sa iyang binuhatan. May mga tawo nga nagpadayon sa pagbuhat ug maayo ug nagtinguha sa himaya, sa kadungganan, ug sa kinabuhing walay kataposan; hatagan sila sa Dios sa kinabuhing dayon'),
  ('1 Cor. 13:2', 'CEB', 'Bisag may hiyas ako sa pagwali nga dinasig, ug makabaton sa tanang kahibalo ug makasabot sa tanang tinago; bisag may pagtuo ako nga makapabalhin sa mga bukid- apan kon wala akoy gugma, wala akoy kapuslanan'),
  ('Gal. 5:6', 'CEB', 'ang importante mao ang pagtuo nga nagbuhat pinaagi sa gugma'),
  ('Mat 28:20', 'CEB', 'tudloi sila sa pagtuman sa tanan nga akong gisugo kaninyo'),
  ('Mat. 7:26', 'CEB', 'Apan ang tanan nga nakadungog sa akong gisulti ug dili magtuman niini, mahisama sa usa ka tawong buangbuang nga nagtukod sa iyang balay diha sa balas'),
  ('Luc. 10:16', 'CEB', 'Ang nagsalikway kaninyo nagsalikway kanako ug sa Amahan nga nagpadala kanako'),
  ('Mar. 16:16', 'CEB', 'Ang motuo ug magpabunyag maluwas, apan ang dili motuo silotan'),
  ('Mat. 7:21', 'CEB', 'Dili ang tanan nga nagtawag kanako, ‘Ginoo, Ginoo’ makasulod sa gingharian sa langit kondili kadto lamang nagtuman sa kabubut-on sa akong Amahan nga atua sa langit'),
  ('Luc. 6:46', 'CEB', 'Nganong nagtawag man kamo kanako, ‘Ginoo, Ginoo’ nga dili man kamo mobuhat sa akong gisugo kaninyo?'),
  ('Jn. 14:15', 'CEB', 'Kon kamo nahigugma kanako, tumana ninyo ang akong mga sugo'),
  ('1 Jn. 5:3', 'CEB', 'Kay ang ilhanan nga gihigugma nato ang Dios mao nga gituman nato ang iyang mga sugo, ug dili lisod tumanon ang iyang mga sugo'),
  ('Jn. 1:17', 'CEB', 'Ang balaod gihatag sa Dios pinaagi kang Moises, apan ang grasya ug ang kamatuoran miabot pinaagi kang Jesu-Cristo'),
  ('Efeso 2:10', 'CEB', 'Kita mga binuhat sa Dios, ug gibuhat kita niya diha kang Cristo Jesus aron magbuhat kitag maayo nga maoy iyang tuyo alang kanato'),
  ('2 Cor. 6:1', 'CEB', 'naghangyo kami kaninyo nga dili ninyo usikan ang grasya sa Dios nga inyong nadawat'),
  ('Fil. 2:12', 'CEB', 'Padayon kamo pagpaningkamot uban sa kahadlok ug pagtahod aron paghingpit sa inyong kaluwasan'),
  ('1 Cor. 10:12', 'CEB', 'Ang naghunahuna nga siya lig-on magbantay nga dili siya mapukan'),
  ('1 Cor. 9:27', 'CEB', 'Gimanso ko ang akong lawas pinaagig mga sumbag ug gipanton ko kini aron dili ako isalikway human ako mag-awhag sa uban sa pag-apil sa bangga'),
  ('Rom. 11:22', 'CEB', 'Makita nato dinhi ang pagkamaluluy-on ug pagkaestrikto sa Dios. Estrikto siya niadtong nangapukan, apan maluluy-on kanimo- kon magpabilin ka sa iyang kaluoy; kay kon dili putlon ka usab'),
  ('Rom. 5:5', 'CEB', 'Kining paglaoma dili gayod mapakyas kay gibubo man sa Dios ang iyang gugma sulod sa tong mga kasingkasing pinaagi sa Espiritu Santo nga gasa sa Dios kanato'),
  ('Rom. 8:24', 'CEB', 'Kay giluwas kita tungod sa paglaom, apan kon makita na nato ang atong gilaoman, dili kana nato matawag nga paglaom. Kay laoman pa ba diay ang nakita na?')
